function renderCards() {
  const container = document.getElementById('cardsContainer');
  const frag = document.createDocumentFragment();
  cards.forEach(c => frag.appendChild(createCardElement(c)));
  container.appendChild(frag);
}

function createCardElement(card) {
  const div = document.createElement('div');
  div.className = 'card';
  div.dataset.id = card.id;
  div.dataset.correct = card.correct;
  div.dataset.mastered = 'false';
  const stars = Array.from({length: 3}, (_, i) =>
    `<span class="star${i < card.stars ? ' filled' : ''}">★</span>`).join('');
  const signImg = card.sign
    ? `<img src="${card.sign}" alt="${card.tag}" style="width:130px;display:block;margin-bottom:10px;border-radius:6px">`
    : '';
  const icon = card.correct === '○' ? '✅' : '❌';
  div.innerHTML = `
    <div class="card-header">
      <span class="card-tag ${card.tagClass}">${card.tag}</span>
      <div class="stars" onclick="setStars(this, event)">${stars}</div>
    </div>
    <div class="card-body">
      ${signImg}
      <p class="question-text">${card.question}</p>
    </div>
    <div class="card-answer wrong">
      <span class="answer-icon">${icon}</span>
      <span class="answer-text">${card.answer}</span>
    </div>
    <div class="card-footer">
      <button class="mastered-btn" onclick="toggleMastered(this)">✓ 标记已掌握</button>
    </div>`;
  return div;
}
